descriptor.controllerScript:
var ctx,ti;
var C={'RUNNING':'#00e676','running':'#00e676','1':'#00e676','STOPPED':'#ff5252','stopped':'#ff5252','0':'#ff5252','IDLE':'#ffb300','idle':'#ffb300','ALARM':'#ff1744','alarm':'#ff1744','FAULT':'#ff1744','fault':'#ff1744'};
function p2(n){return String(n).padStart(2,'0')}
self.onInit=function(){
  ctx=self.ctx;
  ctx.$scope.sc='#334155';ctx.$scope.st='LOADING';
  ctx.$scope.sp='--';ctx.$scope.pc='--';ctx.$scope.pg='--';ctx.$scope.clk='--:--:--';
  ti=setInterval(function(){var d=new Date();ctx.$scope.clk=p2(d.getHours())+':'+p2(d.getMinutes())+':'+p2(d.getSeconds());ctx.detectChanges();},1000);
};
self.onDataUpdated=function(){
  try{
    var v={};
    for(var i=0;i<ctx.data.length;i++){var d=ctx.data[i];if(d&&d.dataKey&&d.data&&d.data.length)v[d.dataKey.name]=d.data[d.data.length-1][1];}
    var s=String(v.machine_state||'UNKNOWN');
    ctx.$scope.st=s.toUpperCase().slice(0,12);
    ctx.$scope.sc=C[s]||C[s.toUpperCase()]||'#3b82f6';
    ctx.$scope.sp=v.spindle_speed?Math.round(parseFloat(v.spindle_speed)):'--';
    ctx.$scope.pc=v.part_count?Math.round(parseFloat(v.part_count)):'--';
    ctx.$scope.pg=v.program_no||'--';
    ctx.detectChanges();
  }catch(e){}
};
self.onDestroy=function(){if(ti)clearInterval(ti);};

var ctx;
var DEFS=[
  {key:'machine_state',icon:'🔄',lbl:'State',unit:'',max:1,isStr:true,colors:{RUNNING:'#00e676',running:'#00e676',STOPPED:'#ff5252',stopped:'#ff5252',IDLE:'#ffb300',idle:'#ffb300',ALARM:'#ff1744'}},
  {key:'spindle_speed',icon:'⚡',lbl:'Spindle',unit:'rpm',max:3000,color:'#00e676'},
  {key:'feed_rate',icon:'🎯',lbl:'Feed Rate',unit:'mm/m',max:500,color:'#ffb300'},
  {key:'part_count',icon:'📦',lbl:'Parts',unit:'pcs',max:900,color:'#3b82f6'},
  {key:'last_cycle_time_sec',icon:'⏱',lbl:'Cycle',unit:'s',max:120,color:'#a78bfa'},
  {key:'alarm_active',icon:'🔔',lbl:'Alarm',unit:'',max:1,isAlarm:true}
];
self.onInit=function(){
  ctx=self.ctx;
  ctx.$scope.cards=DEFS.map(function(d){return{icon:d.icon,lbl:d.lbl,unit:d.unit,val:'--',color:'#334155',pct:0};});
};
self.onDataUpdated=function(){
  try{
    var v={};
    for(var i=0;i<ctx.data.length;i++){var d=ctx.data[i];if(d&&d.dataKey&&d.data&&d.data.length)v[d.dataKey.name]=d.data[d.data.length-1][1];}
    ctx.$scope.cards=DEFS.map(function(def){
      var raw=v[def.key];
      var card={icon:def.icon,lbl:def.lbl,unit:def.unit,val:'--',color:'#334155',pct:0};
      if(raw===undefined||raw===null)return card;
      if(def.isStr){
        var s=String(raw).toUpperCase().slice(0,8);
        card.val=s;card.unit='';
        card.color=def.colors[String(raw)]||def.colors[s]||'#3b82f6';
        card.pct=card.color==='#00e676'?100:card.color==='#ffb300'?50:20;
      } else if(def.isAlarm){
        var on=parseFloat(raw)>0||raw===true||raw==='true'||raw==='1';
        card.val=on?'ACTIVE':'OK';card.unit='';
        card.color=on?'#ff1744':'#00e676';card.pct=on?100:0;
      } else {
        var n=parseFloat(raw);
        if(!isNaN(n)){
          card.val=n>=10?Math.round(n).toString():n.toFixed(1);
          var pct=Math.min(100,(n/def.max)*100);
          card.color=def.color||(pct>=75?'#00e676':pct>=40?'#ffb300':'#ff5252');
          card.pct=pct;
        }
      }
      return card;
    });
    ctx.detectChanges();
  }catch(e){}
};
self.onDestroy=function(){};

var ctx;
var RAD=Math.PI/180;
var DEFS=[
  {key:'oee_today',lbl:'OEE'},
  {key:'availability_today',lbl:'Availability'},
  {key:'performance_today',lbl:'Performance'},
  {key:'quality_today',lbl:'Quality'}
];
function arcEndpoint(pct){
  var angle=-220+pct*2.8;
  var r=50;
  var cx=60,cy=85;
  var rad=angle*RAD;
  return {x:(cx+r*Math.cos(rad)).toFixed(2),y:(cy+r*Math.sin(rad)).toFixed(2),lg:pct>=50?1:0};
}
function makeGauge(def,val){
  var g={lbl:def.lbl,pct:'--',color:'#334155',zone:'NO DATA',lg:0,ex:15,ey:85};
  if(val===undefined||val===null)return g;
  var n=parseFloat(val);
  if(isNaN(n))return g;
  n=Math.max(0,Math.min(100,n));
  g.pct=n.toFixed(1)+'%';
  if(n>=75){g.color='#00e676';g.zone='WORLD CLASS';}
  else if(n>=50){g.color='#ffb300';g.zone='IMPROVING';}
  else{g.color='#ff5252';g.zone='ACTION NEEDED';}
  var ep=arcEndpoint(n);
  g.lg=ep.lg;g.ex=ep.x;g.ey=ep.y;
  return g;
}
self.onInit=function(){
  ctx=self.ctx;
  ctx.$scope.gauges=DEFS.map(function(d){return makeGauge(d,undefined);});
};
self.onDataUpdated=function(){
  try{
    var v={};
    for(var i=0;i<ctx.data.length;i++){var d=ctx.data[i];if(d&&d.dataKey&&d.data&&d.data.length)v[d.dataKey.name]=d.data[d.data.length-1][1];}
    ctx.$scope.gauges=DEFS.map(function(d){return makeGauge(d,v[d.key]);});
    ctx.detectChanges();
  }catch(e){}
};
self.onDestroy=function(){};

var ctx;
var SDEFS=[
  {key:'is_running',lbl:'Running',on:'RUNNING',off:'STOPPED',ca:'#00e676',ci:'#ff5252'},
  {key:'auto_mode',lbl:'Auto Mode',on:'ON',off:'OFF',ca:'#3b82f6',ci:'#64748b'},
  {key:'alarm_active',lbl:'Alarm',on:'ACTIVE',off:'OK',ca:'#ff1744',ci:'#00e676',inv:true},
  {key:'motion_status',lbl:'In Motion',on:'YES',off:'NO',ca:'#ffb300',ci:'#64748b'},
  {key:'emergency',lbl:'Emergency',on:'ACTIVE',off:'CLEAR',ca:'#ff1744',ci:'#00e676',inv:true}
];
function boolOn(raw){return parseFloat(raw)>0||raw===true||raw==='true'||raw==='1'||raw==='RUNNING'||raw==='ON';}
self.onInit=function(){
  ctx=self.ctx;
  ctx.$scope.statuses=SDEFS.map(function(d){return{lbl:d.lbl,val:'--',c:'#334155'};});
  ctx.$scope.pCount='--';ctx.$scope.pTarget='--';ctx.$scope.pPct=0;ctx.$scope.pColor='#334155';ctx.$scope.pAttain='0';
};
self.onDataUpdated=function(){
  try{
    var v={};
    for(var i=0;i<ctx.data.length;i++){var d=ctx.data[i];if(d&&d.dataKey&&d.data&&d.data.length)v[d.dataKey.name]=d.data[d.data.length-1][1];}
    ctx.$scope.statuses=SDEFS.map(function(def){
      var raw=v[def.key];
      if(raw===undefined||raw===null)return{lbl:def.lbl,val:'--',c:'#334155'};
      var on=boolOn(raw);
      return{lbl:def.lbl,val:on?def.on:def.off,c:on?def.ca:def.ci};
    });
    var parts=parseFloat(v.parts_today||v.part_count||0)||0;
    var target=parseFloat(v.target_today||0)||0;
    ctx.$scope.pCount=Math.round(parts);
    ctx.$scope.pTarget=target>0?Math.round(target):'?';
    var pct=target>0?Math.min(100,(parts/target)*100):0;
    ctx.$scope.pPct=pct;
    ctx.$scope.pAttain=pct.toFixed(1);
    ctx.$scope.pColor=pct>=90?'#00e676':pct>=70?'#ffb300':'#ff5252';
    ctx.detectChanges();
  }catch(e){}
};
self.onDestroy=function(){};
